public async Task<IResult> CreatePayment(PaymentRequest req, string idempotencyKey)
{
    if (await _store.TryGetResultAsync(idempotencyKey) is { } cached)
        return Results.Ok(cached);
    var result = await _gateway.ChargeAsync(req);
    await _store.SaveAsync(idempotencyKey, result);
    return Results.Ok(result);
}
